package com.hewei.demoLock;

import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import org.json.JSONArray;
import org.json.JSONObject;

import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.ArrayList;
import java.util.List;

public class PromptFlowActivity extends AppCompatActivity {

    private TextView tvJsonContent;
    private Button btnBack;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_prompt_flow);

        initViews();
        loadJsonContent();
    }

    private void initViews() {
        tvJsonContent = findViewById(R.id.tvJsonContent);
        btnBack = findViewById(R.id.btnBack);

        btnBack.setOnClickListener(v -> finish());
    }

    private void loadJsonContent() {
        new Thread(() -> {
            try {
                // 从 assets 读取 JSON 文件
                BufferedReader reader = new BufferedReader(
                        new InputStreamReader(getAssets().open("prompt_flow.json")));
                StringBuilder stringBuilder = new StringBuilder();
                String line;
                while ((line = reader.readLine()) != null) {
                    stringBuilder.append(line);
                }
                reader.close();

                String jsonString = stringBuilder.toString();

                // 解析并格式化 JSON
                String formattedContent = formatJsonContent(jsonString);

                // 在 UI 线程更新显示
                runOnUiThread(() -> {
                    tvJsonContent.setText(formattedContent);
                });

            } catch (Exception e) {
                e.printStackTrace();
                runOnUiThread(() -> {
                    Toast.makeText(this, "加载失败: " + e.getMessage(), Toast.LENGTH_LONG).show();
                    tvJsonContent.setText("加载失败: " + e.getMessage());
                });
            }
        }).start();
    }

    /**
     * 格式化 JSON 内容为易读的文本
     */
    private String formatJsonContent(String jsonString) {
        try {
            JSONObject jsonObject = new JSONObject(jsonString);
            return formatJsonObject(jsonObject, 0);
        } catch (Exception e) {
            // 如果解析失败，尝试作为数组解析
            try {
                JSONArray jsonArray = new JSONArray(jsonString);
                return formatJsonArray(jsonArray, 0);
            } catch (Exception e2) {
                // 如果都失败，返回原始字符串的简单格式化
                return formatRawJson(jsonString);
            }
        }
    }

    private String formatJsonObject(JSONObject obj, int indent) {
        StringBuilder sb = new StringBuilder();
        String indentStr = getIndent(indent);

        try {
            // 获取所有键
            java.util.Iterator<String> keys = obj.keys();
            while (keys.hasNext()) {
                String key = keys.next();
                Object value = obj.get(key);

                sb.append(indentStr).append("📌 ").append(key).append(": ");

                if (value instanceof JSONObject) {
                    sb.append("\n");
                    sb.append(formatJsonObject((JSONObject) value, indent + 1));
                } else if (value instanceof JSONArray) {
                    sb.append("\n");
                    sb.append(formatJsonArray((JSONArray) value, indent + 1));
                } else {
                    sb.append(value).append("\n");
                }
            }
        } catch (Exception e) {
            sb.append(indentStr).append("[解析错误]").append("\n");
        }

        return sb.toString();
    }

    private String formatJsonArray(JSONArray array, int indent) {
        StringBuilder sb = new StringBuilder();
        String indentStr = getIndent(indent);

        try {
            for (int i = 0; i < array.length(); i++) {
                Object value = array.get(i);

                sb.append(indentStr).append("[").append(i + 1).append("] ");

                if (value instanceof JSONObject) {
                    sb.append("\n");
                    sb.append(formatJsonObject((JSONObject) value, indent + 1));
                } else if (value instanceof JSONArray) {
                    sb.append("\n");
                    sb.append(formatJsonArray((JSONArray) value, indent + 1));
                } else {
                    sb.append(value).append("\n");
                }
            }
        } catch (Exception e) {
            sb.append(indentStr).append("[解析错误]").append("\n");
        }

        return sb.toString();
    }

    private String formatRawJson(String jsonString) {
        // 简单格式化：添加换行和缩进
        try {
            JSONObject jsonObj = new JSONObject(jsonString);
            return jsonObj.toString(2);  // 2空格缩进
        } catch (Exception e) {
            try {
                JSONArray jsonArr = new JSONArray(jsonString);
                return jsonArr.toString(2);
            } catch (Exception e2) {
                return jsonString;
            }
        }
    }

    private String getIndent(int level) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < level; i++) {
            sb.append("  ");
        }
        return sb.toString();
    }
}

